const e="quimica",i=JSON.parse(`[{"id":"qui-001","front":"¿Qué son los espectros atómicos?","back":"Son conjuntos de líneas de emisión o absorción características de cada elemento. Indican que la energía electrónica está cuantizada.","topic":"Estructura atómica","difficulty":1,"fromOrientaciones":true},{"id":"qui-002","front":"¿Por qué los espectros atómicos obligaron a revisar los modelos atómicos clásicos?","back":"Porque no podían explicar líneas discretas de energía. Eso llevó a proponer niveles energéticos cuantizados en el átomo.","topic":"Estructura atómica","difficulty":2,"fromOrientaciones":true},{"id":"qui-003","front":"¿Qué diferencia hay entre un espectro de emisión y uno de absorción?","back":"En emisión el átomo emite radiación al descender de nivel; en absorción la absorbe al excitarse. Ambos dependen de la estructura electrónica.","topic":"Estructura atómica","difficulty":1,"fromOrientaciones":true},{"id":"qui-004","front":"¿Cómo se relaciona el modelo de Bohr con los espectros atómicos?","back":"Bohr propuso niveles energéticos cuantizados. La radiación emitida o absorbida cumple ΔE = h·ν.","topic":"Modelo atómico","difficulty":2,"fromOrientaciones":true},{"id":"qui-005","front":"¿Qué expresa la ecuación de Planck en el contexto atómico?","back":"Relaciona la energía de una radiación con su frecuencia: E = h·ν. Explica la cuantización de la energía.","topic":"Modelo atómico","difficulty":1,"fromOrientaciones":true},{"id":"qui-006","front":"¿Qué establece el principio de incertidumbre de Heisenberg?","back":"No se pueden conocer simultáneamente con precisión absoluta la posición y el momento del electrón. Δx·Δp ≥ h/4π.","topic":"Química cuántica","difficulty":2,"fromOrientaciones":true},{"id":"qui-007","front":"¿Qué significa la dualidad onda-corpúsculo del electrón?","back":"Que el electrón presenta comportamiento de partícula y de onda. Por eso no se describe con órbitas exactas, sino con orbitales.","topic":"Química cuántica","difficulty":2,"fromOrientaciones":true},{"id":"qui-008","front":"¿Qué es un orbital atómico?","back":"Es una región del espacio donde hay alta probabilidad de encontrar un electrón. No es una trayectoria fija como la órbita de Bohr.","topic":"Química cuántica","difficulty":1,"fromOrientaciones":true},{"id":"qui-009","front":"¿Qué indican los números cuánticos de un electrón?","back":"Describen su nivel de energía, subnivel, orientación del orbital y espín. Son n, l, m y s.","topic":"Química cuántica","difficulty":2,"fromOrientaciones":true},{"id":"qui-010","front":"¿Qué valores puede tomar el número cuántico principal n?","back":"Toma valores enteros positivos: n = 1, 2, 3... Indica el nivel energético principal y el tamaño del orbital.","topic":"Química cuántica","difficulty":1,"fromOrientaciones":true},{"id":"qui-011","front":"¿Qué determina el número cuántico secundario l?","back":"Determina el subnivel y la forma del orbital. Para un nivel n, l puede valer entre 0 y n−1.","topic":"Química cuántica","difficulty":2,"fromOrientaciones":true},{"id":"qui-012","front":"¿Qué representa el número cuántico magnético m?","back":"Representa la orientación espacial del orbital. Para un valor de l, m toma valores entre −l y +l.","topic":"Química cuántica","difficulty":2,"fromOrientaciones":true},{"id":"qui-013","front":"¿Qué expresa el número cuántico de espín s?","back":"Indica el giro del electrón. Solo puede tomar dos valores: +1/2 o −1/2.","topic":"Química cuántica","difficulty":1,"fromOrientaciones":true},{"id":"qui-014","front":"¿Qué establece el principio de exclusión de Pauli?","back":"Que en un átomo no puede haber dos electrones con los cuatro números cuánticos iguales. Cada orbital admite como máximo 2 electrones.","topic":"Configuración electrónica","difficulty":1,"fromOrientaciones":true},{"id":"qui-015","front":"¿Qué indica la regla de Hund?","back":"Que los orbitales degenerados se ocupan primero con electrones desapareados y espines paralelos antes de empezar a aparearse.","topic":"Configuración electrónica","difficulty":1,"fromOrientaciones":true},{"id":"qui-016","front":"¿Cómo se escribe la configuración electrónica del oxígeno?","back":"Z = 8 → 1s2 2s2 2p4. Se distribuyen los electrones siguiendo Aufbau, Pauli y Hund.","topic":"Configuración electrónica","difficulty":1,"fromOrientaciones":true},{"id":"qui-017","front":"¿Cómo se escribe la configuración electrónica del sodio?","back":"Z = 11 → 1s2 2s2 2p6 3s1. Su electrón diferenciador está en 3s.","topic":"Configuración electrónica","difficulty":1,"fromOrientaciones":true},{"id":"qui-018","front":"¿Cómo se usa el diagrama de Moeller para escribir configuraciones electrónicas?","back":"Se siguen los subniveles en orden creciente de energía: 1s, 2s, 2p, 3s, 3p, 4s, 3d... hasta colocar todos los electrones.","topic":"Configuración electrónica","difficulty":2,"fromOrientaciones":true},{"id":"qui-019","front":"¿Qué es el número atómico?","back":"Es el número de protones del núcleo. En un átomo neutro coincide con el número de electrones.","topic":"Estructura atómica","difficulty":1,"fromOrientaciones":true},{"id":"qui-020","front":"¿Qué es el número másico?","back":"Es la suma de protones y neutrones del núcleo: A = Z + N.","topic":"Estructura atómica","difficulty":1,"fromOrientaciones":true},{"id":"qui-021","front":"¿Cómo se determina el periodo de un elemento a partir de su configuración electrónica?","back":"Por el mayor valor de n presente en su configuración. Ese valor indica el periodo del elemento.","topic":"Tabla periódica","difficulty":2,"fromOrientaciones":true},{"id":"qui-022","front":"¿Cómo se determina el grupo de un elemento representativo a partir de su configuración electrónica?","back":"Se observan los electrones de valencia en los subniveles s y p. Esa distribución permite ubicarlo en su grupo.","topic":"Tabla periódica","difficulty":2,"fromOrientaciones":true},{"id":"qui-023","front":"¿Cómo varía el radio atómico en un periodo?","back":"Disminuye de izquierda a derecha, porque aumenta la carga nuclear efectiva y los electrones son atraídos con más fuerza.","topic":"Tabla periódica","difficulty":1,"fromOrientaciones":true},{"id":"qui-024","front":"¿Cómo varía el radio atómico en un grupo?","back":"Aumenta al descender, porque hay más capas electrónicas y mayor apantallamiento.","topic":"Tabla periódica","difficulty":1,"fromOrientaciones":true},{"id":"qui-025","front":"¿Cómo varía la energía de ionización en un periodo?","back":"Generalmente aumenta de izquierda a derecha. Cuesta más arrancar un electrón cuanto mayor es la carga nuclear efectiva.","topic":"Tabla periódica","difficulty":1,"fromOrientaciones":true},{"id":"qui-026","front":"¿Cómo varía la electronegatividad en un grupo?","back":"Disminuye al descender, porque el átomo atrae peor a los electrones compartidos al aumentar el tamaño y el apantallamiento.","topic":"Tabla periódica","difficulty":1,"fromOrientaciones":true},{"id":"qui-027","front":"¿Qué es la afinidad electrónica?","back":"Es la energía asociada a la ganancia de un electrón por un átomo gaseoso. Suele hacerse más favorable hacia la derecha del periodo.","topic":"Tabla periódica","difficulty":2,"fromOrientaciones":true},{"id":"qui-028","front":"¿Cómo se justifica la reactividad de un elemento a partir de su posición en la tabla periódica?","back":"Por su tendencia a ganar, perder o compartir electrones según su configuración de valencia. Los alcalinos y halógenos son muy reactivos.","topic":"Tabla periódica","difficulty":2,"fromOrientaciones":true},{"id":"qui-029","front":"¿Qué es la carga nuclear efectiva?","back":"Es la atracción neta que siente un electrón por el núcleo tras considerar el apantallamiento de otros electrones.","topic":"Tabla periódica","difficulty":2,"fromOrientaciones":true},{"id":"qui-030","front":"¿Cuál es la configuración electrónica del elemento del tercer periodo de mayor radio atómico?","back":"Es el sodio: 1s2 2s2 2p6 3s1. En un periodo, el radio disminuye de izquierda a derecha.","topic":"Configuración electrónica","difficulty":2,"fromOrientaciones":true},{"id":"qui-031","front":"¿Cuál es la configuración electrónica del elemento del grupo 14 de menor carácter metálico?","back":"Es el carbono: 1s2 2s2 2p2. En el grupo 14, el carácter metálico aumenta al descender.","topic":"Configuración electrónica","difficulty":2,"fromOrientaciones":true},{"id":"qui-032","front":"¿Qué es un enlace iónico?","back":"Es la atracción electrostática entre iones de signo opuesto, originada tras cesión y captura de electrones, normalmente entre metal y no metal.","topic":"Enlace químico","difficulty":1,"fromOrientaciones":true},{"id":"qui-033","front":"¿Qué es un enlace covalente?","back":"Es la compartición de pares de electrones entre átomos, normalmente no metálicos, para alcanzar mayor estabilidad.","topic":"Enlace químico","difficulty":1,"fromOrientaciones":true},{"id":"qui-034","front":"¿Qué es un enlace metálico?","back":"Es la atracción entre cationes metálicos y una nube de electrones deslocalizados. Explica conductividad y maleabilidad.","topic":"Enlace químico","difficulty":1,"fromOrientaciones":true},{"id":"qui-035","front":"¿Cómo se justifica la estabilidad de una molécula con la regla del octeto?","back":"Los átomos tienden a completar 8 electrones en su capa de valencia, salvo excepciones como H, Be o B.","topic":"Enlace químico","difficulty":1,"fromOrientaciones":true},{"id":"qui-036","front":"¿Qué es una estructura de Lewis?","back":"Es una representación que muestra electrones de valencia, enlaces y pares libres de una molécula o ion.","topic":"Enlace covalente","difficulty":1,"fromOrientaciones":true},{"id":"qui-037","front":"¿Cómo se representa la molécula de CO2 mediante Lewis?","back":"O=C=O, con dos enlaces dobles y dos pares libres en cada oxígeno. El carbono central no tiene pares libres.","topic":"Enlace covalente","difficulty":2,"fromOrientaciones":true},{"id":"qui-038","front":"¿Qué predice la teoría RPECV?","back":"Predice la geometría molecular minimizando la repulsión entre pares electrónicos de la capa de valencia del átomo central.","topic":"Geometría molecular","difficulty":1,"fromOrientaciones":true},{"id":"qui-039","front":"¿Qué geometría presenta una molécula con 2 pares enlazantes y 2 pares libres en el átomo central?","back":"Presenta geometría angular. La disposición electrónica es tetraédrica, pero la forma molecular es doblada.","topic":"Geometría molecular","difficulty":2,"fromOrientaciones":true},{"id":"qui-040","front":"¿Qué geometría presenta PF3 según RPECV?","back":"Trigonal piramidal. El P tiene 3 enlaces P–F y 1 par libre, por lo que la disposición electrónica es tetraédrica.","topic":"Geometría molecular","difficulty":2,"fromOrientaciones":true},{"id":"qui-041","front":"¿Por qué BF3 es una molécula apolar?","back":"Porque su geometría trigonal plana es simétrica y los momentos dipolares de los enlaces B–F se anulan entre sí.","topic":"Polaridad molecular","difficulty":2,"fromOrientaciones":true},{"id":"qui-042","front":"¿Cómo se determina si una molécula es polar?","back":"Se analiza la polaridad de sus enlaces y su geometría. Si el momento dipolar resultante no se anula, la molécula es polar.","topic":"Polaridad molecular","difficulty":2,"fromOrientaciones":true},{"id":"qui-043","front":"¿Qué hibridación presenta el átomo central del metano?","back":"sp3. El carbono forma 4 enlaces σ equivalentes con geometría tetraédrica.","topic":"Hibridación","difficulty":1,"fromOrientaciones":true},{"id":"qui-044","front":"¿Qué hibridación presenta el átomo central del eteno?","back":"sp2. Cada carbono forma 3 enlaces σ y queda un orbital p sin hibridar para el enlace π.","topic":"Hibridación","difficulty":2,"fromOrientaciones":true},{"id":"qui-045","front":"¿Qué hibridación presenta el átomo central del etino?","back":"sp. Cada carbono forma 2 enlaces σ y quedan 2 orbitales p para los 2 enlaces π del triple enlace.","topic":"Hibridación","difficulty":2,"fromOrientaciones":true},{"id":"qui-046","front":"¿Qué diferencia hay entre enlace σ y enlace π?","back":"El σ se forma por solapamiento frontal y permite libre giro; el π por solapamiento lateral y restringe el giro.","topic":"Hibridación","difficulty":2,"fromOrientaciones":true},{"id":"qui-047","front":"¿Qué es la energía reticular?","back":"Es la energía liberada al formar 1 mol de cristal iónico a partir de iones gaseosos, o la necesaria para separarlo en esos iones.","topic":"Cristales iónicos","difficulty":2,"fromOrientaciones":true},{"id":"qui-048","front":"¿Para qué se usa el ciclo de Born-Haber?","back":"Para calcular energías reticulares aplicando la ley de Hess a etapas como atomización, ionización, afinidad electrónica y formación del cristal.","topic":"Cristales iónicos","difficulty":2,"fromOrientaciones":true},{"id":"qui-049","front":"¿Qué propiedades presentan los compuestos iónicos?","back":"Altos puntos de fusión, solubilidad frecuente en agua y conductividad eléctrica en fusión o disolución, pero no en estado sólido.","topic":"Cristales iónicos","difficulty":1,"fromOrientaciones":true},{"id":"qui-050","front":"¿Cómo explica el modelo del gas electrónico el enlace metálico?","back":"Los electrones de valencia están deslocalizados formando una nube que mantiene unidos a los cationes metálicos.","topic":"Cristales metálicos","difficulty":2,"fromOrientaciones":true},{"id":"qui-051","front":"¿Por qué los metales conducen bien la electricidad?","back":"Porque poseen electrones deslocalizados que pueden moverse por la red metálica al aplicar una diferencia de potencial.","topic":"Cristales metálicos","difficulty":1,"fromOrientaciones":true},{"id":"qui-052","front":"¿Qué explica la teoría de bandas en los metales?","back":"Explica que existen bandas de energía parcialmente ocupadas o solapadas, lo que permite la movilidad electrónica y la conductividad.","topic":"Cristales metálicos","difficulty":3,"fromOrientaciones":true},{"id":"qui-053","front":"¿Qué son las fuerzas de dispersión de London?","back":"Son interacciones débiles entre dipolos instantáneos e inducidos. Aparecen en todas las moléculas, especialmente en las apolares.","topic":"Fuerzas intermoleculares","difficulty":1,"fromOrientaciones":true},{"id":"qui-054","front":"¿Qué son las fuerzas dipolo-dipolo?","back":"Son atracciones entre moléculas polares por sus dipolos permanentes. Suelen ser más intensas que las de London en moléculas de tamaño parecido.","topic":"Fuerzas intermoleculares","difficulty":1,"fromOrientaciones":true},{"id":"qui-055","front":"¿Qué es un enlace de hidrógeno?","back":"Es una interacción intensa entre H unido a F, O o N y un par libre de otra molécula. Eleva puntos de ebullición y fusión.","topic":"Fuerzas intermoleculares","difficulty":1,"fromOrientaciones":true},{"id":"qui-056","front":"¿Por qué el agua tiene un punto de ebullición más alto que el H2S?","back":"Porque entre sus moléculas hay enlaces de hidrógeno. En H2S predominan fuerzas dipolo-dipolo y de dispersión más débiles.","topic":"Fuerzas intermoleculares","difficulty":2,"fromOrientaciones":true},{"id":"qui-057","front":"¿Cómo influyen las fuerzas intermoleculares en la solubilidad?","back":"Las sustancias se disuelven mejor en disolventes con interacciones similares. Regla útil: semejante disuelve a semejante.","topic":"Fuerzas intermoleculares","difficulty":2,"fromOrientaciones":true},{"id":"qui-058","front":"¿Cómo se nombra Fe2O3 según la IUPAC?","back":"Óxido de hierro(III). El hierro actúa con número de oxidación +3.","topic":"Nomenclatura inorgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-059","front":"¿Cuál es la fórmula del ácido sulfúrico?","back":"H2SO4. Es un oxoácido fuerte y muy importante industrialmente.","topic":"Nomenclatura inorgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-060","front":"¿Cuál es la fórmula del nitrato de calcio?","back":"Ca(NO3)2. Se forma por Ca2+ y dos aniones nitrato NO3−.","topic":"Nomenclatura inorgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-061","front":"¿Cómo se formula el cloruro de aluminio?","back":"AlCl3. El catión Al3+ se combina con tres aniones Cl−.","topic":"Nomenclatura inorgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-062","front":"¿Qué establece el primer principio de la termodinámica?","back":"Que la energía se conserva. La variación de energía interna cumple ΔU = q + w, según el criterio de signos usado.","topic":"Termodinámica","difficulty":2,"fromOrientaciones":true},{"id":"qui-063","front":"¿Qué es la entalpía de reacción?","back":"Es el calor intercambiado a presión constante en una reacción química. Se representa como ΔH.","topic":"Termodinámica","difficulty":1,"fromOrientaciones":true},{"id":"qui-064","front":"¿Cómo se identifica una reacción exotérmica a partir de ΔH?","back":"Si ΔH < 0, la reacción libera calor y es exotérmica.","topic":"Termodinámica","difficulty":1,"fromOrientaciones":true},{"id":"qui-065","front":"¿Cómo se identifica una reacción endotérmica a partir de ΔH?","back":"Si ΔH > 0, la reacción absorbe calor y es endotérmica.","topic":"Termodinámica","difficulty":1,"fromOrientaciones":true},{"id":"qui-066","front":"¿Qué es una ecuación termoquímica?","back":"Es una ecuación química que incluye el valor de la entalpía de reacción y el estado físico de las sustancias.","topic":"Termodinámica","difficulty":1,"fromOrientaciones":true},{"id":"qui-067","front":"¿Para qué sirve la ley de Hess?","back":"Permite calcular ΔH de una reacción sumando entalpías de etapas intermedias: ΔHtotal = ΣΔHparciales.","topic":"Termodinámica","difficulty":2,"fromOrientaciones":true},{"id":"qui-068","front":"¿Cómo se calcula la entalpía de reacción a partir de entalpías de formación?","back":"ΔH°rxn = Σn·ΔHf°(productos) − Σn·ΔHf°(reactivos). Se usan coeficientes estequiométricos.","topic":"Termodinámica","difficulty":2,"fromOrientaciones":true},{"id":"qui-069","front":"¿Cómo se calcula la entalpía de reacción a partir de energías de enlace?","back":"ΔH ≈ ΣE(enlaces rotos) − ΣE(enlaces formados). Romper enlaces consume energía y formarlos la libera.","topic":"Termodinámica","difficulty":2,"fromOrientaciones":true},{"id":"qui-070","front":"¿Qué es la entropía?","back":"Es una magnitud relacionada con el desorden o dispersión de la energía en un sistema. Se representa como S.","topic":"Termodinámica","difficulty":1,"fromOrientaciones":true},{"id":"qui-071","front":"¿Cómo suele variar la entropía cuando un sólido pasa a gas?","back":"Aumenta notablemente, porque el estado gaseoso presenta mayor desorden y más libertad de movimiento.","topic":"Termodinámica","difficulty":1,"fromOrientaciones":true},{"id":"qui-072","front":"¿Qué es la energía libre de Gibbs?","back":"Es la magnitud que permite predecir la espontaneidad: ΔG = ΔH − T·ΔS.","topic":"Termodinámica","difficulty":2,"fromOrientaciones":true},{"id":"qui-073","front":"¿Cuándo es espontánea una reacción según ΔG?","back":"Cuando ΔG < 0. Si ΔG > 0 no es espontánea en ese sentido, y si ΔG = 0 está en equilibrio.","topic":"Termodinámica","difficulty":1,"fromOrientaciones":true},{"id":"qui-074","front":"¿Cómo influye la temperatura en la espontaneidad de una reacción con ΔH > 0 y ΔS > 0?","back":"Será espontánea a temperaturas altas, porque el término T·ΔS puede superar a ΔH en ΔG = ΔH − T·ΔS.","topic":"Termodinámica","difficulty":3,"fromOrientaciones":true},{"id":"qui-075","front":"¿Qué es la velocidad de reacción?","back":"Es la variación de concentración de reactivos o productos por unidad de tiempo. Ejemplo: v = −Δ[A]/Δt.","topic":"Cinética química","difficulty":1,"fromOrientaciones":true},{"id":"qui-076","front":"¿Qué explica la teoría de las colisiones?","back":"Que para reaccionar las partículas deben chocar con energía suficiente y orientación adecuada.","topic":"Cinética química","difficulty":1,"fromOrientaciones":true},{"id":"qui-077","front":"¿Qué es la energía de activación?","back":"Es la energía mínima que deben superar los reactivos para que la colisión sea eficaz y se forme el complejo activado.","topic":"Cinética química","difficulty":1,"fromOrientaciones":true},{"id":"qui-078","front":"¿Cómo afecta un aumento de temperatura a la velocidad de reacción?","back":"Suele aumentarla, porque crece la energía cinética y el número de colisiones eficaces.","topic":"Cinética química","difficulty":1,"fromOrientaciones":true},{"id":"qui-079","front":"¿Cómo afecta un catalizador a una reacción química?","back":"Disminuye la energía de activación y acelera la reacción, sin consumirse ni modificar ΔH ni la posición del equilibrio.","topic":"Cinética química","difficulty":2,"fromOrientaciones":true},{"id":"qui-080","front":"¿Cuál es el orden total de una reacción con ley de velocidad v = k·[A]2·[B]?","back":"Es 3. El orden total es la suma de los exponentes: 2 + 1 = 3.","topic":"Cinética química","difficulty":2,"fromOrientaciones":true},{"id":"qui-081","front":"¿Qué unidades tiene la constante de velocidad en una reacción con ley v = k·[A]2·[B]?","back":"Como el orden total es 3, las unidades de k son L2·mol−2·s−1, para que v quede en mol·L−1·s−1.","topic":"Cinética química","difficulty":3,"fromOrientaciones":true},{"id":"qui-082","front":"¿Cómo afecta un aumento de concentración de reactivos a la velocidad de reacción?","back":"Suele aumentar la velocidad, porque crece el número de colisiones entre partículas por unidad de tiempo.","topic":"Cinética química","difficulty":1,"fromOrientaciones":true},{"id":"qui-083","front":"¿Cómo influye la superficie de contacto en la velocidad de reacción?","back":"A mayor superficie de contacto, mayor velocidad, porque hay más partículas expuestas para colisionar.","topic":"Cinética química","difficulty":1,"fromOrientaciones":true},{"id":"qui-084","front":"¿Qué es el equilibrio químico?","back":"Es un estado dinámico en el que las velocidades de la reacción directa e inversa son iguales y las concentraciones permanecen constantes.","topic":"Equilibrio químico","difficulty":1,"fromOrientaciones":true},{"id":"qui-085","front":"¿Qué expresa la constante de equilibrio Kc?","back":"Relaciona las concentraciones molares de productos y reactivos en equilibrio, elevadas a sus coeficientes estequiométricos.","topic":"Equilibrio químico","difficulty":1,"fromOrientaciones":true},{"id":"qui-086","front":"¿Cuál es la expresión de Kc para aA + bB ⇌ cC + dD?","back":"Kc = [C]c·[D]d / ([A]a·[B]b). No se incluyen sólidos ni líquidos puros.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-087","front":"¿Qué es Kp?","back":"Es la constante de equilibrio expresada en función de las presiones parciales de las especies gaseosas.","topic":"Equilibrio químico","difficulty":1,"fromOrientaciones":true},{"id":"qui-088","front":"¿Cómo se relacionan Kp y Kc?","back":"Kp = Kc·(R·T)Δn, donde Δn es moles gaseosos de productos menos moles gaseosos de reactivos.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-089","front":"¿Qué es el cociente de reacción Q?","back":"Tiene la misma expresión que K, pero usando concentraciones o presiones en cualquier instante, no solo en equilibrio.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-090","front":"¿Cómo evoluciona un sistema si Q < K?","back":"Evoluciona hacia la derecha, formando más productos, hasta alcanzar el equilibrio.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-091","front":"¿Cómo evoluciona un sistema si Q > K?","back":"Evoluciona hacia la izquierda, consumiendo productos y formando reactivos hasta llegar al equilibrio.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-092","front":"¿Qué establece el principio de Le Châtelier?","back":"Cuando un sistema en equilibrio sufre una perturbación, se desplaza en el sentido que tiende a contrarrestarla.","topic":"Equilibrio químico","difficulty":1,"fromOrientaciones":true},{"id":"qui-093","front":"¿Cómo afecta un aumento de concentración de un reactivo al equilibrio?","back":"El equilibrio se desplaza hacia la derecha, favoreciendo la formación de productos para consumir el reactivo añadido.","topic":"Equilibrio químico","difficulty":1,"fromOrientaciones":true},{"id":"qui-094","front":"¿Cómo afecta un aumento de presión a un equilibrio gaseoso?","back":"El equilibrio se desplaza hacia el lado con menor número de moles gaseosos, si ambos lados tienen distinto número de moles.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-095","front":"¿Cómo afecta un aumento de temperatura a un equilibrio endotérmico?","back":"Desplaza el equilibrio hacia la derecha, porque el calor actúa como reactivo en una reacción endotérmica.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-096","front":"¿Cómo afecta un aumento de temperatura a un equilibrio exotérmico?","back":"Desplaza el equilibrio hacia la izquierda, porque el calor actúa como producto en una reacción exotérmica.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-097","front":"¿Qué ocurre con Kc cuando cambia la temperatura?","back":"Kc solo cambia con la temperatura. No varía por cambios de concentración, presión o catalizador.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-098","front":"¿Cómo afecta un catalizador a un equilibrio químico?","back":"No modifica la posición del equilibrio ni el valor de K. Solo acelera por igual las reacciones directa e inversa.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-099","front":"¿Qué es un equilibrio heterogéneo?","back":"Es un equilibrio en el que intervienen especies en distintos estados físicos, por ejemplo sólido y disolución acuosa.","topic":"Equilibrio químico","difficulty":1,"fromOrientaciones":true},{"id":"qui-100","front":"¿Qué es el producto de solubilidad Kps?","back":"Es la constante de equilibrio de la disolución de una sal poco soluble. Solo incluye las especies disueltas.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-101","front":"¿Cuál es la expresión de Kps para AgCl(s) ⇌ Ag+ + Cl−?","back":"Kps = [Ag+][Cl−]. El sólido AgCl no aparece en la expresión.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-102","front":"¿Cómo se relaciona la solubilidad molar s con Kps en una sal AB?","back":"Para AB(s) ⇌ A+ + B−, si la solubilidad es s, entonces Kps = s2.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-103","front":"¿Cómo afecta el ion común a la solubilidad de una sal poco soluble?","back":"La solubilidad disminuye, porque el equilibrio de disolución se desplaza hacia la izquierda.","topic":"Equilibrio químico","difficulty":2,"fromOrientaciones":true},{"id":"qui-104","front":"¿Qué es un ácido según Arrhenius?","back":"Es una sustancia que en agua aumenta la concentración de H3O+ o H+.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-105","front":"¿Qué es una base según Arrhenius?","back":"Es una sustancia que en agua aumenta la concentración de OH−.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-106","front":"¿Qué es un ácido según Brønsted-Lowry?","back":"Es una especie capaz de ceder protones H+.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-107","front":"¿Qué es una base según Brønsted-Lowry?","back":"Es una especie capaz de aceptar protones H+.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-108","front":"¿Qué es un par ácido-base conjugado?","back":"Es un par de especies que se diferencian en un protón. Ejemplo: NH4+/NH3.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-109","front":"¿Qué diferencia hay entre un ácido fuerte y uno débil?","back":"El ácido fuerte se disocia prácticamente por completo en agua; el débil solo lo hace parcialmente.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-110","front":"¿Qué diferencia hay entre una base fuerte y una débil?","back":"La base fuerte se disocia prácticamente por completo en agua; la débil establece un equilibrio de ionización.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-111","front":"¿Qué es el grado de disociación α?","back":"Es la fracción de moléculas iniciales que se ionizan. Se expresa como α = moles disociados / moles iniciales.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-112","front":"¿Cómo se define el pH?","back":"pH = −log[H3O+]. Mide la acidez de una disolución acuosa.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-113","front":"¿Cómo se define el pOH?","back":"pOH = −log[OH−]. En agua a 25 °C se cumple pH + pOH = 14.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-114","front":"¿Cuál es la expresión de Ka para un ácido débil HA?","back":"Ka = [H3O+][A−]/[HA]. Cuanto mayor sea Ka, más fuerte es el ácido.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-115","front":"¿Cuál es la expresión de Kb para una base débil B?","back":"Kb = [BH+][OH−]/[B]. Cuanto mayor sea Kb, más fuerte es la base.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-116","front":"¿Qué valor tiene Kw a 25 °C?","back":"Kw = [H3O+][OH−] = 10−14.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-117","front":"¿Cuál es el pH de una disolución con [H3O+] = 1,0·10−3 M?","back":"pH = −log(10−3) = 3.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-118","front":"¿Cuál es el pH de una disolución con [OH−] = 1,0·10−2 M?","back":"pOH = 2 y pH = 14 − 2 = 12, a 25 °C.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-119","front":"¿Qué es la hidrólisis de una sal?","back":"Es la reacción de los iones de una sal con el agua, que puede originar disoluciones ácidas o básicas.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-120","front":"¿Qué carácter presenta una sal formada por ácido fuerte y base fuerte?","back":"Presenta disolución aproximadamente neutra, porque sus iones apenas hidrolizan.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-121","front":"¿Qué carácter presenta una sal formada por ácido fuerte y base débil?","back":"Presenta carácter ácido, porque el catión conjugado de la base débil hidroliza y genera H3O+.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-122","front":"¿Qué carácter presenta una sal formada por ácido débil y base fuerte?","back":"Presenta carácter básico, porque el anión conjugado del ácido débil hidroliza y genera OH−.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-123","front":"¿Qué es una neutralización?","back":"Es la reacción entre un ácido y una base. En forma iónica neta: H3O+ + OH− → 2H2O.","topic":"Ácido-base","difficulty":1,"fromOrientaciones":true},{"id":"qui-124","front":"¿Qué es una volumetría ácido-base?","back":"Es una técnica para determinar la concentración de un ácido o base haciendo reaccionar un volumen medido con otra disolución de concentración conocida.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-125","front":"¿Qué se cumple en el punto de equivalencia de una valoración ácido-base?","back":"Que han reaccionado cantidades estequiométricas de ácido y base según la ecuación ajustada.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-126","front":"¿Cómo se calcula una concentración en una neutralización ácido fuerte-base fuerte 1:1?","back":"En el punto de equivalencia se cumple Ma·Va = Mb·Vb, si la estequiometría es 1:1.","topic":"Ácido-base","difficulty":2,"fromOrientaciones":true},{"id":"qui-127","front":"¿Qué es una reacción redox?","back":"Es una reacción en la que hay transferencia de electrones y cambian los números de oxidación.","topic":"Reacciones redox","difficulty":1,"fromOrientaciones":true},{"id":"qui-128","front":"¿Qué diferencia hay entre oxidación y reducción?","back":"Oxidación: pérdida de electrones o aumento del número de oxidación. Reducción: ganancia de electrones o disminución del número de oxidación.","topic":"Reacciones redox","difficulty":1,"fromOrientaciones":true},{"id":"qui-129","front":"¿Qué es el agente oxidante?","back":"Es la especie que provoca la oxidación de otra y, al hacerlo, se reduce.","topic":"Reacciones redox","difficulty":1,"fromOrientaciones":true},{"id":"qui-130","front":"¿Qué es el agente reductor?","back":"Es la especie que provoca la reducción de otra y, al hacerlo, se oxida.","topic":"Reacciones redox","difficulty":1,"fromOrientaciones":true},{"id":"qui-131","front":"¿Cómo se ajusta una reacción redox por el método del ion-electrón?","back":"Se separan las semirreacciones, se ajustan átomos y cargas con H2O, H+ u OH− y e−, y luego se suman eliminando electrones.","topic":"Reacciones redox","difficulty":3,"fromOrientaciones":true},{"id":"qui-132","front":"¿Qué es el potencial estándar de reducción?","back":"Es la tendencia de una especie a reducirse en condiciones estándar. Se expresa como E°.","topic":"Electroquímica","difficulty":2,"fromOrientaciones":true},{"id":"qui-133","front":"¿Cómo se calcula el potencial estándar de una pila?","back":"E°pila = E°cátodo − E°ánodo, usando potenciales estándar de reducción.","topic":"Electroquímica","difficulty":2,"fromOrientaciones":true},{"id":"qui-134","front":"¿Cuándo es espontáneo un proceso electroquímico en una pila?","back":"Cuando E°pila > 0. Entonces ΔG° = −n·F·E° es negativa.","topic":"Electroquímica","difficulty":2,"fromOrientaciones":true},{"id":"qui-135","front":"¿Qué relación hay entre energía libre de Gibbs y fuerza electromotriz?","back":"Se relacionan mediante ΔG = −n·F·E. Si E es positiva, el proceso es espontáneo en una pila galvánica.","topic":"Electroquímica","difficulty":3,"fromOrientaciones":true},{"id":"qui-136","front":"¿Qué ocurre en el ánodo de una pila galvánica?","back":"Tiene lugar la oxidación. Los electrones salen del ánodo hacia el circuito externo.","topic":"Electroquímica","difficulty":1,"fromOrientaciones":true},{"id":"qui-137","front":"¿Qué ocurre en el cátodo de una pila galvánica?","back":"Tiene lugar la reducción. Los electrones llegan al cátodo desde el circuito externo.","topic":"Electroquímica","difficulty":1,"fromOrientaciones":true},{"id":"qui-138","front":"¿Cómo se representa una pila Daniell?","back":"Zn(s) | Zn2+(aq) || Cu2+(aq) | Cu(s). El Zn se oxida y el Cu2+ se reduce.","topic":"Electroquímica","difficulty":2,"fromOrientaciones":true},{"id":"qui-139","front":"¿Qué es una cuba electrolítica?","back":"Es un sistema en el que una corriente externa fuerza una reacción redox no espontánea.","topic":"Electroquímica","difficulty":2,"fromOrientaciones":true},{"id":"qui-140","front":"¿Qué establece la primera ley de Faraday?","back":"La masa depositada o liberada en un electrodo es proporcional a la carga eléctrica que circula: Q = I·t.","topic":"Electroquímica","difficulty":2,"fromOrientaciones":true},{"id":"qui-141","front":"¿Cómo se calcula la cantidad de sustancia depositada en una electrólisis?","back":"n = Q / (z·F), donde Q es la carga, z el número de electrones y F la constante de Faraday.","topic":"Electroquímica","difficulty":3,"fromOrientaciones":true},{"id":"qui-142","front":"¿Cómo se calcula la carga eléctrica que circula en una electrólisis?","back":"Q = I·t, donde I es la intensidad en amperios y t el tiempo en segundos.","topic":"Electroquímica","difficulty":2,"fromOrientaciones":true},{"id":"qui-143","front":"¿Qué es la corrosión de un metal?","back":"Es su deterioro por oxidación, generalmente favorecido por el medio. El hierro se oxida formando óxidos e hidróxidos.","topic":"Electroquímica","difficulty":1,"fromOrientaciones":true},{"id":"qui-144","front":"¿Cómo puede prevenirse la corrosión del hierro?","back":"Mediante recubrimientos, galvanización, protección catódica o uso de aleaciones resistentes.","topic":"Electroquímica","difficulty":2,"fromOrientaciones":true},{"id":"qui-145","front":"¿Qué es un grupo funcional en química orgánica?","back":"Es un átomo o conjunto de átomos que determina las propiedades y reactividad características de una familia de compuestos orgánicos.","topic":"Química orgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-146","front":"¿Qué es una serie homóloga?","back":"Es un conjunto de compuestos con el mismo grupo funcional y propiedades semejantes, que difieren en unidades –CH2–.","topic":"Química orgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-147","front":"¿Qué es la isomería de cadena?","back":"Es la que presentan compuestos con la misma fórmula molecular pero distinta disposición del esqueleto carbonado.","topic":"Isomería orgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-148","front":"¿Qué es la isomería de posición?","back":"Es la que presentan compuestos con igual fórmula molecular y grupo funcional, pero situado en distinta posición.","topic":"Isomería orgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-149","front":"¿Qué es la isomería de función?","back":"Es la que presentan compuestos con la misma fórmula molecular pero distinto grupo funcional.","topic":"Isomería orgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-150","front":"¿Qué es la isomería geométrica?","back":"Es una estereoisomería debida a la falta de giro libre en dobles enlaces o ciclos. Da lugar a formas cis/trans o E/Z.","topic":"Isomería orgánica","difficulty":2,"fromOrientaciones":true},{"id":"qui-151","front":"¿Qué es la isomería óptica?","back":"Es la que presentan moléculas quirales no superponibles con su imagen especular, llamadas enantiómeros.","topic":"Isomería orgánica","difficulty":2,"fromOrientaciones":true},{"id":"qui-152","front":"¿Cómo se nombra CH3CH2OH?","back":"Etanol. Es un alcohol de dos carbonos con grupo funcional –OH.","topic":"Nomenclatura orgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-153","front":"¿Cómo se nombra CH3COOH?","back":"Ácido etanoico. También se conoce como ácido acético.","topic":"Nomenclatura orgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-154","front":"¿Cómo se nombra CH3COOCH2CH3?","back":"Etanoato de etilo. Es un éster formado por ácido etanoico y etanol.","topic":"Nomenclatura orgánica","difficulty":2,"fromOrientaciones":true},{"id":"qui-155","front":"¿Qué es una reacción de combustión de un compuesto orgánico?","back":"Es su reacción con O2 para formar, de manera completa, CO2 y H2O. Ejemplo: CH4 + 2O2 → CO2 + 2H2O.","topic":"Reactividad orgánica","difficulty":1,"fromOrientaciones":true},{"id":"qui-156","front":"¿Qué ocurre en una reacción de adición a un doble enlace?","back":"Se rompe el enlace π y se añaden átomos o grupos al doble enlace. Ejemplo: CH2=CH2 + H2 → CH3–CH3.","topic":"Reactividad orgánica","difficulty":2,"fromOrientaciones":true},{"id":"qui-157","front":"¿Qué ocurre en la adición de HBr al eteno?","back":"Se forma bromoetano: CH2=CH2 + HBr → CH3–CH2Br.","topic":"Reactividad orgánica","difficulty":2,"fromOrientaciones":true},{"id":"qui-158","front":"¿Qué es una reacción de sustitución en química orgánica?","back":"Es una reacción en la que un átomo o grupo del compuesto se reemplaza por otro. Es típica en alcanos y compuestos aromáticos.","topic":"Reactividad orgánica","difficulty":2,"fromOrientaciones":true},{"id":"qui-159","front":"¿Qué es una reacción de esterificación?","back":"Es una reacción de condensación entre un ácido carboxílico y un alcohol para formar un éster y agua. R–COOH + R'–OH → R–COOR' + H2O.","topic":"Reactividad orgánica","difficulty":2,"fromOrientaciones":true},{"id":"qui-160","front":"¿Qué normas básicas de seguridad deben seguirse en el laboratorio de química?","back":"Usar bata, gafas y material adecuado; no pipetear con la boca; manipular y eliminar reactivos y residuos siguiendo las normas de seguridad.","topic":"Laboratorio químico","difficulty":1,"fromOrientaciones":true}]`),a={subject:e,flashcards:i};export{a as default,i as flashcards,e as subject};
